    @classmethod
    def format_slot(cls, start_time: datetime.datetime, end_time: datetime.datetime) -> str:
        return '{start_time:%a. %-d %b, %H:%M} - {end_time:%H:%M}'.format(
            start_time=start_time, end_time=end_time
        )

    @classmethod
    def format_duration(cls, total_seconds: int | float) -> str:
        resolutions = [('d', 60 * 60 * 24), ('h', 60 * 60), (' min', 60)]
        result = ''
        remainder = int(total_seconds)
        for display, res in resolutions:
            value, remainder = divmod(remainder, res)
            if value:
                result += f' {value}{display}'

        return result.strip()

