You'll also need to register the `get_google_event_link` function as a database function. Add this to your models.py:

```python
from django.db import connection
from django.db.models import Func

class GoogleEventLink(Func):
    function = 'get_google_event_link'

# Register the function with PostgreSQL
def register_google_event_link():
    with connection.cursor() as cursor:
        cursor.execute("""
        CREATE OR REPLACE FUNCTION get_google_event_link(event_id text)
        RETURNS text AS $$
        DECLARE
            calendar_id text := %s;
            formatted_id text;
            encoded_id text;
        BEGIN
            IF event_id IS NULL OR calendar_id IS NULL THEN
                RETURN NULL;
            END IF;

            formatted_id := event_id || ' ' || calendar_id;
            encoded_id := encode(formatted_id::bytea, 'base64');
            encoded_id := regexp_replace(encoded_id, '=+$', '');

            RETURN 'https://www.google.com/calendar/event?eid=' || encoded_id;
        END;
        $$ LANGUAGE plpgsql;
        """, [settings.GOOGLE_FIELD_SALES_EVENT_OWNER_CALENDAR_ID])
```

